import { AutkSpatialDb } from 'autk-db';

const db = new AutkSpatialDb();
await db.init();

await db.loadOsm({
    queryArea: { geocodeArea: 'Chicago', areas: ['Loop', 'Near South Side'] },
    outputTableName: 'table_osm',
    autoLoadLayers: {
        coordinateFormat: 'EPSG:3395',
        layers: ['surface', 'parks', 'water', 'roads', 'buildings'],
        dropOsmTable: true,
    },
});

await db.loadCsv({
    csvFileUrl: 'https://raw.githubusercontent.com/urban-toolkit/autark/main/usecases/public/data/shadows_chicago.csv',
    outputTableName: 'shadows',
    geometryColumns: { latColumnName: 'latitude', longColumnName: 'longitude', coordinateFormat: 'EPSG:3395' },
});

const layers = [];
for (const layer of db.getLayerTables()) {
    layers.push({ name: layer.name, type: layer.type, geojson: await db.getLayer(layer.name) });
}
return layers;

// Per-road shadow metric via GPU shader. Full WGSL lives upstream at
//   usecases/src/shadows/shadow.wgsl
// Paste it into wgslBody when running the full analysis.

const roads = arg.find(l => l.name === 'table_osm_roads')?.geojson;
if (!roads) throw new Error('roads layer missing');

// Pick a representative footprint + height to demonstrate; in the full
// analysis these come from a building selected via map picking.
const buildings = arg.find(l => l.name === 'table_osm_buildings')?.geojson;
const sample = buildings?.features?.[0];
const footprint = sample?.geometry?.coordinates?.[0]?.flat() ?? [0, 0];
const height = sample?.properties?.height ?? 30;

const wgslBody = /* paste shadow.wgsl here */ `
  return vec2f(0.0, 0.0);
`;

const geojsonCompute = new ComputeGpgpu();
const computedRoads = await geojsonCompute.run({
    collection: roads,
    variableMapping: { seg: 'geometry.coordinates', sjoin_avg: 'sjoin.avg.6' },
    attributeMatrices: { seg: { rows: 'auto', cols: 2 } },
    uniforms: { bld_height: height, doy: 172 },
    uniformMatrices: { ring: { data: footprint, cols: 2 } },
    outputColumns: ['shadow', 'contribution'],
    wgslBody,
});

return arg.map(l => l.name === 'table_osm_roads' ? { ...l, geojson: computedRoads } : l);

// Render layers and color roads by shadow contribution.
const map = new AutkMap(container);
await map.init();
for (const layer of arg) {
    map.loadCollection(layer.name, { collection: layer.geojson, type: layer.type });
}
map.updateRenderInfo('table_osm_buildings', { isPick: true });
map.updateRenderInfo('table_osm_roads', { isColorMap: true });
map.updateThematic('table_osm_roads', {
    collection: arg.find(l => l.name === 'table_osm_roads').geojson,
    property: 'properties.compute.contribution',
});
map.draw();
return map;

// Brushable histogram of shadow values across road segments.
const roads = arg.find(l => l.name === 'table_osm_roads')?.geojson ?? arg[0]?.geojson;
return new AutkChart(container, {
    type: 'barchart',
    collection: roads,
    attributes: { axis: ['sjoin.avg.6', '@transform'] },
    labels: { axis: ['Hours of shadow', '#Road segments'], title: 'Shadow distribution' },
    width: 600,
    height: 380,
    events: ['brushX'],
    transform: { preset: 'binning-1d', options: { bins: 13 } },
});
